BEGIN;

DROP TABLE IF EXISTS "maintenance", "voiture", "user";

CREATE TABLE "user" (
  "id" INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  "pseudo" VARCHAR(255) NOT NULL UNIQUE,
  "email" VARCHAR(255) NOT NULL UNIQUE,
  "password" TEXT NOT NULL,
  "avatar_url" VARCHAR(255),
  "created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMPTZ
);


CREATE TABLE "voiture" (
  "id" INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  "marque" VARCHAR(100) NOT NULL,
  "modele" VARCHAR(100) NOT NULL,
  "immatriculation" VARCHAR(20) NOT NULL,
  "image_url" VARCHAR(255),
  "user_id" INTEGER NOT NULL REFERENCES "user"("id") ON DELETE CASCADE,
  "created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMPTZ
);


CREATE TABLE "maintenance" (
  "id" INTEGER PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  "categorie" VARCHAR(50),
  "date" DATE NOT NULL,
  "kilometrage" INTEGER NOT NULL,
  "description" TEXT,
  "facture_url" VARCHAR(255),
  "est_obsolete" BOOLEAN DEFAULT FALSE,
  "voiture_id" INTEGER NOT NULL REFERENCES "voiture"("id") ON DELETE CASCADE,
  "parent_id" INTEGER NULL REFERENCES "maintenance"("id") ON DELETE SET NULL, -- SET NULL est plus sûr ici que CASCADE
  "created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMPTZ
);


COMMIT;